TriggerOraclev10g.body:
DECLARE
    v_cod_error               NUMBER;
    v_mensaje_error           VARCHAR2 (1000);
    vro_cita                  tkr_citas%ROWTYPE;
    vro_servicio_solicitado   tkr_servicios_solicitados%ROWTYPE;
BEGIN
    IF (:old.id_estado_consulta = 1 AND :new.id_estado_consulta = 2)
    THEN
        pkgln_google.p_grabar_consulta ('Citas',:new.id_cita, v_cod_error, v_mensaje_error);

        IF pkgtkr_citas_dao.f_existe (:new.id_cita, vro_cita) = TRUE
        THEN
            IF     vro_cita.id_solicitud_atencion IS NOT NULL
               AND pkgtkr_servicios_solicitados_dao.f_existe (vro_cita.id_solicitud_atencion,
                                                              vro_servicio_solicitado) =
                   TRUE
            THEN
                vro_servicio_solicitado.id_estado_servicio := 2;
                pkgtkr_servicios_solicitados_dao.p_actualizar (vro_servicio_solicitado);
            END IF;
        END IF;
    END IF;
END;
